queries.sparql:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFunctions ?child ; p:hasHealth_Apps ?parent . } GROUP BY ?child }
  ?child p:value ?value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Health_Apps } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFunctions ?child ; p:hasHealth_Apps ?parent . } GROUP BY ?child }
  ?child p:value ?value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Health_Apps } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?value WHERE {
  ?health_apps_functions a :Health_Apps_Functions .
  ?functions a :Functions .
  ?health_apps_functions p:hasFunctions ?functions .
  ?health_apps a :Health_Apps .
  ?health_apps_functions p:hasHealth_Apps ?health_apps .
  ?health_apps p:name ?name .
  ?functions p:value ?value .
} }
}
